import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

describe("@feature", () => {
  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_feature
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T003.T003_01
    it("Products.<Product>.Features.<Feature> namespace", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @feature
        namespace Products.MyProduct.Features.MyFeature;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T003.T003_02
    it("@invariant ops inline in feature block", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        namespace Products.MyProduct.Entities.Task {
          @entity
          model Task { id: string; }
        }
        using Products.MyProduct.Entities.Task;

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} always has an id.",
            why: "Addressability.",
          })
          op task_has_id(): void;
        }
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T003.T003_03
    it("missing .Features. segment", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @feature
        namespace Products.MyProduct.MyFeature;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Features/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T003.T003_04
    it("not starting with Products.", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @feature
        namespace Features.MyFeature;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Products\./,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T003.T003_05
    it("bare namespace without hierarchy", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @feature
        namespace MyFeature;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T003.T003_06
    it("too many segments (Products.P.Features.F.Extra)", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @feature
        namespace Products.MyProduct.Features.MyFeature.Extra;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
      });
    });
  });
});
